{
    "level": "A2–B1",
    "intro": "У цій темі ти навчишся розпізнавати <strong>stative verbs</strong> — дієслова, які описують <strong>стан</strong>, а не активну дію.",
    "rules": [
        {
            "label": "STATE, NOT ACTION",
            "color": "emerald",
            "text": "Stative verbs говорять про думку, почуття, володіння, сприйняття або стан.",
            "example": "know, believe, own, love, seem"
        },
        {
            "label": "USUALLY NOT CONTINUOUS",
            "color": "blue",
            "text": "Такі дієслова <strong>зазвичай не ставимо в Continuous</strong>.",
            "example": "I know the answer. not I am knowing the answer."
        },
        {
            "label": "SOME VERBS CHANGE MEANING",
            "color": "amber",
            "text": "Деякі дієслова можуть бути stative або dynamic залежно від значення.",
            "example": "I think he is right. / I am thinking about the problem."
        }
    ]
}

{
    "title": "1. Основні групи",
    "intro": "Найчастіше дієслова стану можна зібрати в кілька груп.",
    "items": [
        {
            "label": "Thinking / opinion",
            "title": "know, believe, understand, remember",
            "subtitle": "думка, знання, розуміння"
        },
        {
            "label": "Possession",
            "title": "have, own, belong, need",
            "subtitle": "володіння або належність"
        },
        {
            "label": "Senses / perception",
            "title": "see, hear, smell, taste, seem",
            "subtitle": "сприйняття або враження"
        },
        {
            "label": "Emotions / state",
            "title": "love, like, hate, want, prefer",
            "subtitle": "емоції, бажання, стан"
        }
    ]
}

{
    "title": "2. Коли вживати stative verbs",
    "sections": [
        {
            "label": "Думка і знання",
            "color": "emerald",
            "description": "Для ідей, переконань, пам’яті й розуміння зазвичай беремо <strong>simple form</strong>, а не continuous.",
            "examples": [
                {
                    "en": "I know her name.",
                    "ua": "Я знаю її ім'я."
                },
                {
                    "en": "We believe you.",
                    "ua": "Ми тобі віримо."
                },
                {
                    "en": "She understands the rule.",
                    "ua": "Вона розуміє правило."
                }
            ]
        },
        {
            "label": "Володіння і належність",
            "color": "blue",
            "description": "Коли дієслово показує, що хтось <strong>має</strong>, <strong>володіє</strong> або щось <strong>належить</strong> комусь, continuous зазвичай не потрібен.",
            "examples": [
                {
                    "en": "They own a small cafe.",
                    "ua": "Вони мають маленьке кафе."
                },
                {
                    "en": "This bag belongs to me.",
                    "ua": "Ця сумка належить мені."
                },
                {
                    "en": "I need more time.",
                    "ua": "Мені потрібно більше часу."
                }
            ]
        },
        {
            "label": "Сприйняття та емоції",
            "color": "amber",
            "description": "Дієслова відчуттів, враження та емоцій теж часто поводяться як stative verbs.",
            "examples": [
                {
                    "en": "I see the problem now.",
                    "ua": "Я бачу проблему зараз."
                },
                {
                    "en": "This soup tastes great.",
                    "ua": "Цей суп чудовий на смак."
                },
                {
                    "en": "She loves jazz.",
                    "ua": "Вона любить джаз."
                }
            ]
        }
    ]
}

{
    "title": "3. Коли Continuous можливий",
    "sections": [
        {
            "label": "Meaning change",
            "color": "violet",
            "description": "Деякі дієслова можуть мати <strong>інше значення</strong> у continuous form і тоді стають dynamic.",
            "examples": [
                {
                    "en": "I think he is right.",
                    "ua": "Я думаю, що він має рацію."
                },
                {
                    "en": "I am thinking about our next trip.",
                    "ua": "Я думаю про нашу наступну подорож."
                },
                {
                    "en": "She has a new laptop.",
                    "ua": "У неї є новий ноутбук."
                },
                {
                    "en": "She is having lunch.",
                    "ua": "Вона обідає."
                }
            ]
        },
        {
            "label": "Be careful with see / taste / smell",
            "color": "sky",
            "description": "Якщо мова про загальне сприйняття, дієслово часто stative. Якщо про активну дію, continuous можливий.",
            "examples": [
                {
                    "en": "I see what you mean.",
                    "ua": "Я розумію, що ти маєш на увазі."
                },
                {
                    "en": "The chef is tasting the sauce.",
                    "ua": "Шеф-кухар пробує соус."
                },
                {
                    "en": "I smell smoke.",
                    "ua": "Я відчуваю запах диму."
                }
            ],
            "note": "Питай себе, чи це стан / враження, чи реальна дія в процесі."
        }
    ]
}

{
    "title": "4. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Continuous із типовим дієсловом стану.",
            "wrong": "I am knowing the answer.",
            "right": "✅ <span class=\"font-mono\">I know the answer.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Continuous із дієсловом почуття у базовому значенні.",
            "wrong": "She is loving jazz.",
            "right": "✅ <span class=\"font-mono\">She loves jazz.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Не помічати зміну значення.",
            "wrong": "I think about it now = I think he is right.",
            "right": "✅ <span class=\"font-mono\">I think he is right.</span> / <span class=\"font-mono\">I am thinking about it now.</span>"
        }
    ]
}

